181‚Üí
182‚Üí    class Result private constructor(question: String?, answer: String?) {
183‚Üí        val question: String = question ?: VALUE_USE_DEFAULT
184‚Üí        val answer: String = answer ?: VALUE_USE_DEFAULT
185‚Üí
186‚Üí        fun applyTo(template: JSONObject) {
187‚Üí            template.put("bqfmt", question)
188‚Üí            template.put("bafmt", answer)
189‚Üí        }
190‚Üí
191‚Üí        companion object {
192‚Üí            @Contract("null -> null")
193‚Üí            fun fromIntent(intent: Intent?): Result? {
194‚Üí                return if (intent == null) {
195‚Üí                    null
196‚Üí                } else {
197‚Üí                    try {
198‚Üí                        val question = intent.getStringExtra(INTENT_QUESTION_FORMAT)
199‚Üí                        val answer = intent.getStringExtra(INTENT_ANSWER_FORMAT)
200‚Üí                        Result(question, answer)
201‚Üí                    } catch (e: Exception) {
202‚Üí                        Timber.w(e, "Could not read result from intent")
203‚Üí                        null
204‚Üí                    }
205‚Üí                }
206‚Üí            }
207‚Üí        }
208‚Üí    }
209‚Üí
210‚Üí    companion object {
211‚Üí        const val INTENT_QUESTION_FORMAT = "bqfmt"
212‚Üí        const val INTENT_ANSWER_FORMAT = "bafmt"
213‚Üí
214‚Üí        /** Specified the card browser should use the default template formatter  */
215‚Üí        const val VALUE_USE_DEFAULT = ""
216‚Üí
217‚Üí        @CheckResult
218‚Üí        fun getIntentFromTemplate(context: Context, template: JSONObject): Intent {
219‚Üí            val browserQuestionTemplate = template.getString("bqfmt")
220‚Üí            val browserAnswerTemplate = template.getString("bafmt")
221‚Üí            return getIntent(context, browserQuestionTemplate, browserAnswerTemplate)
222‚Üí        }
223‚Üí
224‚Üí        @CheckResult
225‚Üí        fun getIntent(context: Context, questionFormat: String, answerFormat: String): Intent {
226‚Üí            return Intent(context, CardTemplateBrowserAppearanceEditor::class.java).apply {
227‚Üí                putExtra(INTENT_QUESTION_FORMAT, questionFormat)
228‚Üí                putExtra(INTENT_ANSWER_FORMAT, answerFormat)
229‚Üí            }
230‚Üí        }
231‚Üí    }
232‚Üí}
