 39‚Üíobject CollectionManager {
 40‚Üí    /**
 41‚Üí     * The currently active backend, which is created on demand via [ensureBackend], and
 42‚Üí     * implicitly via [ensureOpen] and routines like [withCol].
 43‚Üí     * The backend is long-lived, and will generally only be closed when switching interface
 44‚Üí     * languages or changing schema versions. A closed backend cannot be reused, and a new one
 45‚Üí     * must be created.
 46‚Üí     */
 47‚Üí    private var backend: Backend? = null
 48‚Üí
 49‚Üí    /**
 50‚Üí     * The current collection, which is opened on demand via [withCol]. If you need to
 51‚Üí     * close and reopen the collection in an atomic operation, add a new method that
 52‚Üí     * calls [withQueue], and then executes [ensureClosedInner] and [ensureOpenInner] inside it.
 53‚Üí     * A closed collection can be detected via [withOpenColOrNull] or by checking [Collection.dbClosed].
 54‚Üí     */
 55‚Üí    private var collection: Collection? = null
 56‚Üí
 57‚Üí    private var queue: CoroutineDispatcher = Dispatchers.IO.limitedParallelism(1)
 58‚Üí
 59‚Üí    @VisibleForTesting
 60‚Üí    var emulateOpenFailure = false
 61‚Üí
 62‚Üí    /** A speed optimisation to remove the logging function of the collection */
 63‚Üí    @VisibleForTesting
 64‚Üí    var disableLogFile: Boolean = false
 65‚Üí
 66‚Üí    /**
 67‚Üí     * Execute the provided block on a serial background queue, to ensure
 68‚Üí     * concurrent access does not happen.
 69‚Üí     *
 70‚Üí     * The background queue is run in a [Dispatchers.IO] context.
 71‚Üí     * It's important that the block is not suspendable - if it were, it would allow
 72‚Üí     * multiple requests to be interleaved when a suspend point was hit.
 73‚Üí     *
 74‚Üí     * TODO Disallow running functions that are supposed to be run inside the queue outside of it.
 75‚Üí     *   For instance, this can be done by marking a [block] with a context
 76‚Üí     *   that cannot be instantiated outside of this class:
 77‚Üí     *
 78‚Üí     *       suspend fun<T> withQueue(block: context(Queue) () -> T): T {
 79‚Üí     *          return withContext(collectionOperationsDispatcher) {
 80‚Üí     *              block(queue)
 81‚Üí     *          }
 82‚Üí     *      }
 83‚Üí     *
 84‚Üí     *   Then, only functions that are also marked can be run inside the block:
 85‚Üí     *
 86‚Üí     *       context(Queue) suspend fun canOnlyBeRunInWithQueue()
 87‚Üí     */
 88‚Üí    private suspend fun<T> withQueue(@WorkerThread block: CollectionManager.() -> T): T {
 89‚Üí        return withContext(queue) {
 90‚Üí            this@CollectionManager.block()
 91‚Üí        }
 92‚Üí    }
 93‚Üí
 94‚Üí    /**
 95‚Üí     * Execute the provided block with the collection, opening if necessary.
 96‚Üí     *
 97‚Üí     * Calls are serialized, and run in background [Dispatchers.IO] thread.
 98‚Üí     *
 99‚Üí     * Parallel calls to this function are guaranteed to be serialized, so you can be
100‚Üí     * sure the collection won't be closed or modified by another thread. This guarantee
101‚Üí     * does not hold if legacy code calls [getColUnsafe].
102‚Üí     */
103‚Üí    suspend fun <T> withCol(@WorkerThread block: Collection.() -> T): T {
104‚Üí        return withQueue {
105‚Üí            ensureOpenInner()
106‚Üí            block(collection!!)
107‚Üí        }
108‚Üí    }
109‚Üí
110‚Üí    /**
111‚Üí     * Execute the provided block if the collection is already open. See [withCol] for more.
112‚Üí     * Since the block may return a null value, and a null value will also be returned in the
113‚Üí     * case of the collection being closed, if the calling code needs to distinguish between
114‚Üí     * these two cases, it should wrap the return value of the block in a class (eg Optional),
115‚Üí     * instead of returning a nullable object.
