156‚Üí    /**
157‚Üí     * Close the currently cached backend and discard it. Useful when enabling the V16 scheduler in the
158‚Üí     * dev preferences, or if the active language changes. Saves and closes the collection if open.
159‚Üí     */
160‚Üí    suspend fun discardBackend() {
161‚Üí        withQueue {
162‚Üí            discardBackendInner()
163‚Üí        }
164‚Üí    }
