166‚Üí    /** See [discardBackend]. This must only be run inside the queue. */
167‚Üí    private fun discardBackendInner() {
168‚Üí        ensureClosedInner()
169‚Üí        if (backend != null) {
170‚Üí            backend!!.close()
171‚Üí            backend = null
172‚Üí        }
173‚Üí    }
174‚Üí
175‚Üí    /**
176‚Üí     * Open the backend if it's not already open.
177‚Üí     */
178‚Üí    private suspend fun ensureBackend() {
179‚Üí        withQueue {
180‚Üí            ensureBackendInner()
181‚Üí        }
182‚Üí    }
183‚Üí
184‚Üí    /** See [ensureBackend]. This must only be run inside the queue. */
185‚Üí    private fun ensureBackendInner() {
186‚Üí        if (backend == null) {
187‚Üí            backend = BackendFactory.getBackend()
188‚Üí        }
189‚Üí    }
190‚Üí
191‚Üí    /**
192‚Üí     * If the collection is open, close it.
193‚Üí     */
194‚Üí    suspend fun ensureClosed() {
195‚Üí        withQueue {
196‚Üí            ensureClosedInner()
197‚Üí        }
198‚Üí    }
199‚Üí
200‚Üí    /** See [ensureClosed]. This must only be run inside the queue. */
201‚Üí    private fun ensureClosedInner() {
202‚Üí        if (collection == null) {
203‚Üí            return
204‚Üí        }
205‚Üí        try {
206‚Üí            collection!!.close()
207‚Üí        } catch (exc: Exception) {
208‚Üí            Timber.e("swallowing error on close: $exc")
209‚Üí        }
210‚Üí        collection = null
211‚Üí    }
212‚Üí
213‚Üí    /**
214‚Üí     * Open the collection, if it's not already open.
215‚Üí     *
216‚Üí     * Automatically called by [withCol]. Can be called directly to ensure collection
217‚Üí     * is loaded at a certain point in time, or to ensure no errors occur.
218‚Üí     */
219‚Üí    private suspend fun ensureOpen() {
220‚Üí        withQueue {
221‚Üí            ensureOpenInner()
222‚Üí        }
223‚Üí    }
224‚Üí
225‚Üí    /** See [ensureOpen]. This must only be run inside the queue. */
226‚Üí    private fun ensureOpenInner() {
227‚Üí        ensureBackendInner()
228‚Üí        if (emulateOpenFailure) {
229‚Üí            throw BackendException.BackendDbException.BackendDbLockedException(backendError {})
230‚Üí        }
231‚Üí        if (collection == null || collection!!.dbClosed) {
232‚Üí            val path = collectionPathInValidFolder()
233‚Üí            collection =
234‚Üí                collection(path, log = !disableLogFile, backend)
235‚Üí        }
236‚Üí    }
