238‚Üí    suspend fun deleteCollectionDirectory() {
239‚Üí        withQueue {
240‚Üí            ensureClosedInner()
241‚Üí            getCollectionDirectory().deleteRecursively()
242‚Üí        }
243‚Üí    }
