245‚Üí    fun getCollectionDirectory() =
246‚Üí        // Allow execution if AnkiDroidApp.instance is not initialized
247‚Üí        File(CollectionHelper.getCurrentAnkiDroidDirectoryOptionalContext(AnkiDroidApp.sharedPrefs()) { AnkiDroidApp.instance })
