264‚Üí    private fun <T> blockForQueue(block: CollectionManager.() -> T): T {
265‚Üí        return if (isRobolectric) {
266‚Üí            block(this)
267‚Üí        } else {
268‚Üí            runBlocking {
269‚Üí                withQueue(block)
270‚Üí            }
271‚Üí        }
272‚Üí    }
