297‚Üí    // using TimeManager breaks a sched test that makes assumptions about the time, so we
298‚Üí    // access the time directly
299‚Üí    @SuppressLint("DirectSystemCurrentTimeMillisUsage")
300‚Üí    private fun <T> logUIHangs(block: () -> T): T {
301‚Üí        val start = System.currentTimeMillis()
302‚Üí        return block().also {
303‚Üí            val elapsed = System.currentTimeMillis() - start
304‚Üí            if (Threads.isOnMainThread && elapsed > 100) {
305‚Üí                val stackTraceElements = Thread.currentThread().stackTrace
306‚Üí                // locate the probable calling file/line in the stack trace, by filtering
307‚Üí                // out our own code, and standard dalvik/java.lang stack frames
308‚Üí                val caller = stackTraceElements.filter {
309‚Üí                    val klass = it.className
310‚Üí                    val toCheck = listOf(
311‚Üí                        "CollectionManager",
312‚Üí                        "dalvik",
313‚Üí                        "java.lang",
314‚Üí                        "CollectionHelper",
315‚Üí                        "AnkiActivity"
316‚Üí                    )
317‚Üí                    for (text in toCheck) {
318‚Üí                        if (text in klass) {
319‚Üí                            return@filter false
320‚Üí                        }
321‚Üí                    }
322‚Üí                    true
323‚Üí                }.first()
324‚Üí                Timber.w("blocked main thread for %dms:\n%s", elapsed, caller)
325‚Üí            }
326‚Üí        }
327‚Üí    }
